class Solution:
    def maxEqualRowsAfterFlips(self, matrix):
        m = len(matrix)
        best = 0
        for i in range(m):
            count = 0
            for j in range(m):
                same = all(matrix[i][k] == matrix[j][k] for k in range(len(matrix[i])))
                opp = all(matrix[i][k] != matrix[j][k] for k in range(len(matrix[i])))
                if same or opp:
                    count += 1
            if count > best:
                best = count
        return best

