class Solution:
    def maxEqualRowsAfterFlips(self, matrix):
        from collections import Counter
        counts = Counter()
        for row in matrix:
            if row[0] == 0:
                key = tuple(row)
            else:
                key = tuple(1 - x for x in row)
            counts[key] += 1
        return max(counts.values())

